import{_ as e,c as t,o as a,a2 as i}from"./chunks/framework.DdOM6S6U.js";const f=JSON.parse('{"title":"Features Pattern","description":"","frontmatter":{"sidebarPos":13,"sidebarTitle":"Features Pattern"},"headers":[],"relativePath":"system-reference/features.md","filePath":"system-reference/features.md","lastUpdated":null}'),s={name:"system-reference/features.md"},o=i(`<h1 id="features-pattern" tabindex="-1">Features Pattern <a class="header-anchor" href="#features-pattern" aria-label="Permalink to &quot;Features Pattern&quot;">​</a></h1><p>Modularity features use a <strong>triple pattern</strong>: Entity trait + Repository trait + Hydrate. Understanding this pattern helps when adding or customizing features.</p><h2 id="pattern-overview" tabindex="-1">Pattern Overview <a class="header-anchor" href="#pattern-overview" aria-label="Permalink to &quot;Pattern Overview&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Config[Route config type: file]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Hydrate[FileHydrate]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Schema[schema type: input-file]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Repo[FilesTrait]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Model[HasFiles]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Config --&gt; Hydrate</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Hydrate --&gt; Schema</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Schema --&gt; Repo</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Repo --&gt; Model</span></span></code></pre></div><ol><li><strong>Route config</strong> defines input with <code>type</code> (e.g. <code>file</code>, <code>image</code>, <code>repeater</code>)</li><li><strong>Hydrate</strong> transforms to frontend schema (<code>input-file</code>, etc.)</li><li><strong>Repository trait</strong> handles persistence in <code>hydrate*Trait</code>, <code>afterSave*Trait</code>, <code>getFormFields*Trait</code></li><li><strong>Entity trait</strong> provides model relationships and accessors</li></ol><h2 id="entity-trait-model" tabindex="-1">Entity Trait (Model) <a class="header-anchor" href="#entity-trait-model" aria-label="Permalink to &quot;Entity Trait (Model)&quot;">​</a></h2><ul><li><strong>Location</strong>: <code>src/Entities/Traits/Has*.php</code> or <code>*.php</code> (e.g. <code>Assignable</code>)</li><li><strong>Purpose</strong>: Relationships, boot logic, accessors, scopes</li><li><strong>Convention</strong>: <code>HasX</code> for &quot;has many/one X&quot;; <code>IsX</code> for behavior (e.g. <code>IsSingular</code>); <code>Xable</code> for &quot;can be X&#39;d&quot; (e.g. <code>Assignable</code>, <code>Processable</code>)</li></ul><p><strong>Example — HasFiles</strong>:</p><ul><li><code>files()</code> — morphToMany File with pivot (role, locale)</li><li><code>file($role, $locale)</code> — URL for first file</li><li><code>filesList($role, $locale)</code> — array of URLs</li><li><code>fileObject($role, $locale)</code> — File model</li></ul><h2 id="repository-trait" tabindex="-1">Repository Trait <a class="header-anchor" href="#repository-trait" aria-label="Permalink to &quot;Repository Trait&quot;">​</a></h2><ul><li><strong>Location</strong>: <code>src/Repositories/Traits/*Trait.php</code></li><li><strong>Purpose</strong>: Persistence hooks called by Repository lifecycle</li><li><strong>Convention</strong>: <code>setColumns*Trait</code>, <code>hydrate*Trait</code>, <code>afterSave*Trait</code>, <code>getFormFields*Trait</code></li></ul><p><strong>Example — FilesTrait</strong>:</p><ul><li><code>setColumnsFilesTrait</code> — registers file columns from inputs with <code>type</code> containing <code>file</code></li><li><code>hydrateFilesTrait</code> — sets <code>$object-&gt;files</code> relation from form data</li><li><code>afterSaveFilesTrait</code> — syncs pivot (attach/updateExistingPivot)</li><li><code>getFormFieldsFilesTrait</code> — loads existing files into form fields</li></ul><h2 id="hydrate" tabindex="-1">Hydrate <a class="header-anchor" href="#hydrate" aria-label="Permalink to &quot;Hydrate&quot;">​</a></h2><ul><li><strong>Location</strong>: <code>src/Hydrates/Inputs/*Hydrate.php</code></li><li><strong>Purpose</strong>: Transform module config into frontend schema</li><li><strong>Convention</strong>: <code>$input[&#39;type&#39;] = &#39;input-{kebab}&#39;</code> (e.g. <code>input-file</code>, <code>input-assignment</code>); some hydrates output <code>select</code> (e.g. AuthorizeHydrate, StateableHydrate); set <code>name</code>, <code>label</code>, <code>items</code>, <code>endpoint</code>, etc.</li></ul><p><strong>Example — FileHydrate</strong>:</p><ul><li><code>requirements</code>: <code>name</code> =&gt; <code>files</code>, <code>translated</code> =&gt; false, <code>default</code> =&gt; []</li><li><code>hydrate()</code>: <code>type</code> → <code>input-file</code>, <code>label</code> → <code>__(&#39;Files&#39;)</code></li></ul><h2 id="adding-a-new-feature" tabindex="-1">Adding a New Feature <a class="header-anchor" href="#adding-a-new-feature" aria-label="Permalink to &quot;Adding a New Feature&quot;">​</a></h2><ol><li><strong>Entity trait</strong>: Add <code>HasMyFeature</code> with relationships and accessors</li><li><strong>Repository trait</strong>: Add <code>MyFeatureTrait</code> with <code>hydrate*</code>, <code>afterSave*</code>, <code>getFormFields*</code></li><li><strong>Hydrate</strong>: Add <code>MyFeatureHydrate</code> extending <code>InputHydrate</code>; set <code>type</code> → <code>input-my-feature</code></li><li><strong>Vue component</strong>: Create <code>VInputMyFeature</code>; register in <code>registry.js</code></li><li><strong>Config</strong>: Add trait to <code>modularity.traits</code> if needed; add input to route config</li></ol><h2 id="feature-dependencies" tabindex="-1">Feature Dependencies <a class="header-anchor" href="#feature-dependencies" aria-label="Permalink to &quot;Feature Dependencies&quot;">​</a></h2><p>Some features compose others:</p><ul><li><strong>HasRepeaters</strong> uses HasFiles, HasImages, HasPriceable, HasFileponds</li><li><strong>HasPayment</strong> uses HasPriceable</li><li><strong>Processable</strong> uses HasFileponds</li></ul><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/guide/module-features/">Module Features Overview</a> — Feature matrix and quick reference</li><li><a href="/system-reference/hydrates">Hydrates</a> — Schema transformation</li><li><a href="/system-reference/repositories">Repositories</a> — Lifecycle and traits</li><li><a href="/system-reference/entities">Entities</a> — Entity traits list</li></ul>`,24),r=[o];function n(l,d,c,p,h,u){return a(),t("div",null,r)}const y=e(s,[["render",n]]);export{f as __pageData,y as default};
